-- ิ๖วิ๖วิ๖ว Zonas Geogr+ํficas ิว๖ zonas dibujadas en mapa ิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖ว-- Tabla independiente de zona/sectores/fincas.-- Almacena geometr+กa como GeoJSON (jsonb), sin PostGIS.-- Cada zona pertenece a una empresa (multi-tenant).create table if not exists public.zonas_geograficas (  id          bigint generated by default as identity primary key,  empresa_id  bigint not null references empresas(id) on delete cascade,  nombre      text not null,  descripcion text,  color       text not null default '#2563eb'::text,  tipo        text not null default 'personalizada'::text,  estado      text not null default 'activa'::text,  geojson     jsonb not null,  area_sqm    numeric,  created_by  bigint not null references usuarios(id) on delete restrict,  updated_by  bigint references usuarios(id) on delete set null,  created_at  timestamptz not null default now(),  updated_at  timestamptz not null default now(),  archived_at timestamptz);-- +์ndicescreate index idx_zonas_geograficas_empresa on public.zonas_geograficas(empresa_id);create index idx_zonas_geograficas_estado  on public.zonas_geograficas(estado);-- updated_at triggercreate or replace function set_zonas_geograficas_updated_at()returns trigger language plpgsql as $$begin  new.updated_at = now();  return new;end;$$;drop trigger if exists zonas_geograficas_updated_at_trigger on public.zonas_geograficas;create trigger zonas_geograficas_updated_at_trigger  before update on public.zonas_geograficas  for each row execute function set_zonas_geograficas_updated_at();-- ิ๖วิ๖วิ๖ว RLS ิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วalter table public.zonas_geograficas enable row level security;-- SELECT: usuarios ven zonas de su empresadrop policy if exists zonas_geograficas_select on public.zonas_geograficas;create policy zonas_geograficas_selecton public.zonas_geograficas for selectusing (empresa_id = public.current_empresa_id());-- INSERT: admin/director pueden crear en su empresadrop policy if exists zonas_geograficas_insert on public.zonas_geograficas;create policy zonas_geograficas_inserton public.zonas_geograficas for insertwith check (  empresa_id = public.current_empresa_id()  and public.is_admin_or_director());-- UPDATE: admin/director pueden modificar en su empresadrop policy if exists zonas_geograficas_update on public.zonas_geograficas;create policy zonas_geograficas_updateon public.zonas_geograficas for updateusing (empresa_id = public.current_empresa_id() and public.is_admin_or_director())with check (empresa_id = public.current_empresa_id() and public.is_admin_or_director());-- DELETE: admin/director pueden eliminar en su empresadrop policy if exists zonas_geograficas_delete on public.zonas_geograficas;create policy zonas_geograficas_deleteon public.zonas_geograficas for deleteusing (empresa_id = public.current_empresa_id() and public.is_admin_or_director());